 77→fn build_project_view(project: &Project, next_action_count: i64) -> ProjectView {
 78→    ProjectView {
 79→        id: project.id().as_uuid().to_string(),
 80→        title: project.title().as_str().to_string(),
 81→        next_action_count,
 82→        is_stalled: next_action_count == 0,
 83→    }
 84→}
