218→pub async fn get_project_detail(
219→    AuthenticatedUser(user_id): AuthenticatedUser,
220→    State(pool): State<PgPool>,
221→    Path(project_id): Path<Uuid>,
222→) -> Result<Response, ProjectError> {
223→    let pid = ProjectId::from_uuid(project_id);
224→
225→    let detail = match project_service::get_project_detail(&pool, &pid, &user_id).await {
226→        Ok(d) => d,
227→        Err(GetProjectError::NotFound) => {
228→            return Ok((
229→                StatusCode::NOT_FOUND,
230→                Html("<h1>Project not found</h1>".to_string()),
231→            )
232→                .into_response())
233→        }
234→        Err(GetProjectError::Unauthorized) => {
235→            return Ok((
236→                StatusCode::FORBIDDEN,
237→                Html("<h1>Not authorized</h1>".to_string()),
238→            )
239→                .into_response())
240→        }
241→        Err(GetProjectError::Unexpected(err)) => return Err(ProjectError::Unexpected(err)),
242→    };
243→
244→    let contexts = context_service::list_contexts(&pool, &user_id)
245→        .await
246→        .map_err(ProjectError::Unexpected)?;
247→
248→    let inbox_count = inbox_service::get_inbox_count(&pool, &user_id)
249→        .await
250→        .map_err(ProjectError::Unexpected)?;
251→
252→    let project_view = build_project_view(&detail.project, detail.active_next_action_count);
253→
254→    let active_actions: Vec<ProjectNextActionView> = detail
255→        .next_actions
256→        .iter()
257→        .filter(|a| a.is_active())
258→        .map(|a| build_action_view(a, &contexts))
259→        .collect();
260→
261→    let completed_actions: Vec<ProjectNextActionView> = detail
262→        .next_actions
263→        .iter()
264→        .filter(|a| a.is_completed())
265→        .map(|a| build_action_view(a, &contexts))
266→        .collect();
267→
268→    let context_options: Vec<ContextOption> = contexts
269→        .iter()
270→        .map(|c| ContextOption {
271→            id: c.id().as_uuid().to_string(),
272→            name: c.name().as_str().to_string(),
273→        })
274→        .collect();
275→
276→    let template = ProjectDetailTemplate {
277→        current_page: "projects",
278→        inbox_count,
279→        project: project_view,
280→        active_actions,
281→        completed_actions,
282→        contexts: context_options,
283→        error_message: None,
284→    };
285→    Ok(Html(template.render()?).into_response())
286→}
