491→pub async fn post_project_next_action(
492→    AuthenticatedUser(user_id): AuthenticatedUser,
493→    State(pool): State<PgPool>,
494→    headers: HeaderMap,
495→    Path(project_id): Path<Uuid>,
496→    Form(form): Form<AddProjectNextActionForm>,
497→) -> Result<Response, ProjectError> {
498→    let htmx = is_htmx_request(&headers);
499→    let pid = ProjectId::from_uuid(project_id);
500→    let context_id = crate::domain::ContextId::from_uuid(form.context_id);
501→
502→    if form.title.trim().is_empty() {
503→        if htmx {
504→            return Ok(StatusCode::NO_CONTENT.into_response());
505→        }
506→        return Ok(Redirect::to(&format!("/projects/{project_id}")).into_response());
507→    }
508→
509→    match project_service::add_next_action_to_project(&pool, &user_id, &pid, context_id, form.title)
510→        .await
511→    {
512→        Ok(action) => {
513→            if htmx {
514→                let contexts = context_service::list_contexts(&pool, &user_id)
515→                    .await
516→                    .map_err(ProjectError::Unexpected)?;
517→
518→                let template = ProjectNextActionItemTemplate {
519→                    action: build_action_view(&action, &contexts),
520→                };
521→                let body = template.render().map_err(ProjectError::Render)?;
522→                Ok(htmx_response_with_announce(
523→                    Html(body),
524→                    "Next action added to project",
525→                ))
526→            } else {
527→                Ok(Redirect::to(&format!("/projects/{project_id}")).into_response())
528→            }
529→        }
530→        Err(AddProjectNextActionError::ProjectNotFound) => Ok((
531→            StatusCode::NOT_FOUND,
532→            Html("<h1>Project not found</h1>".to_string()),
533→        )
534→            .into_response()),
535→        Err(AddProjectNextActionError::Unauthorized) => Ok((
536→            StatusCode::FORBIDDEN,
537→            Html("<h1>Not authorized</h1>".to_string()),
538→        )
539→            .into_response()),
540→        Err(AddProjectNextActionError::InvalidTitle(title_err)) => {
541→            let user_facing = match title_err {
542→                TodoTitleError::Empty => {
543→                    if htmx {
544→                        return Ok(StatusCode::NO_CONTENT.into_response());
545→                    }
546→                    return Ok(Redirect::to(&format!("/projects/{project_id}")).into_response());
547→                }
548→                TodoTitleError::TooLong { max, .. } => {
549→                    format!("That title is too long (max {max} characters)")
550→                }
551→            };
552→            // For now, redirect with error — full re-render would need project detail context
553→            let _ = user_facing;
554→            Ok(Redirect::to(&format!("/projects/{project_id}")).into_response())
555→        }
556→        Err(AddProjectNextActionError::Unexpected(err)) => Err(ProjectError::Unexpected(err)),
557→    }
558→}
559→
560→#[derive(Debug, thiserror::Error)]
561→pub enum ProjectError {
562→    #[error("Failed to render template")]
563→    Render(#[from] askama::Error),
564→    #[error(transparent)]
565→    Unexpected(anyhow::Error),
566→}
567→
568→impl IntoResponse for ProjectError {
569→    fn into_response(self) -> Response {
570→        tracing::error!(error = %self, "Project error");
571→        (
572→            StatusCode::INTERNAL_SERVER_ERROR,
573→            Html("<h1>Something went wrong</h1>".to_string()),
574→        )
575→            .into_response()
576→    }
577→}
