    match project_service::complete_project(&pool, &pid, &user_id).await {
        Ok(()) => {
            if htmx {
                Ok(htmx_response_with_announce(
                    Html(String::new()),
                    "Project completed",
                ))
            } else {
                Ok(Redirect::to("/projects").into_response())
