            .into_response()),
        Err(CompleteProjectError::Unauthorized) => Ok((
            StatusCode::FORBIDDEN,
            Html("<h1>Not authorized</h1>".to_string()),
        )
            .into_response()),
        Err(CompleteProjectError::Unexpected(err)) => Err(ProjectError::Unexpected(err)),
    }
}

