#[derive(serde::Deserialize)]
pub struct AddProjectNextActionForm {
    pub title: String,
    pub context_id: Uuid,
}

pub async fn post_project_next_action(
    AuthenticatedUser(user_id): AuthenticatedUser,
    State(pool): State<PgPool>,
    headers: HeaderMap,
    Path(project_id): Path<Uuid>,
    Form(form): Form<AddProjectNextActionForm>,
) -> Result<Response, ProjectError> {
    let htmx = is_htmx_request(&headers);
    let pid = ProjectId::from_uuid(project_id);
    let context_id = crate::domain::ContextId::from_uuid(form.context_id);

    if form.title.trim().is_empty() {
        if htmx {
            return Ok(StatusCode::NO_CONTENT.into_response());
        }
        return Ok(Redirect::to(&format!("/projects/{project_id}")).into_response());
    }

    match project_service::add_next_action_to_project(&pool, &user_id, &pid, context_id, form.title)
        .await
    {
        Ok(action) => {
            if htmx {
                let contexts = context_service::list_contexts(&pool, &user_id)
                    .await
                    .map_err(ProjectError::Unexpected)?;

                let template = ProjectNextActionItemTemplate {
                    action: build_action_view(&action, &contexts),
                };
                let body = template.render().map_err(ProjectError::Render)?;
                Ok(htmx_response_with_announce(
                    Html(body),
                    "Next action added to project",
                ))
            } else {
                Ok(Redirect::to(&format!("/projects/{project_id}")).into_response())
            }
        }
        Err(AddProjectNextActionError::ProjectNotFound) => Ok((
            StatusCode::NOT_FOUND,
            Html("<h1>Project not found</h1>".to_string()),
        )
            .into_response()),
        Err(AddProjectNextActionError::Unauthorized) => Ok((
            StatusCode::FORBIDDEN,
            Html("<h1>Not authorized</h1>".to_string()),
        )
            .into_response()),
        Err(AddProjectNextActionError::InvalidTitle(title_err)) => {
            let user_facing = match title_err {
                TodoTitleError::Empty => {
                    if htmx {
                        return Ok(StatusCode::NO_CONTENT.into_response());
                    }
                    return Ok(Redirect::to(&format!("/projects/{project_id}")).into_response());
                }
                TodoTitleError::TooLong { max, .. } => {
                    format!("That title is too long (max {max} characters)")
                }
            };
            // For now, redirect with error — full re-render would need project detail context
            let _ = user_facing;
            Ok(Redirect::to(&format!("/projects/{project_id}")).into_response())
        }
        Err(AddProjectNextActionError::Unexpected(err)) => Err(ProjectError::Unexpected(err)),
    }
}

#[derive(Debug, thiserror::Error)]
pub enum ProjectError {
    #[error("Failed to render template")]
    Render(#[from] askama::Error),
    #[error(transparent)]
    Unexpected(anyhow::Error),
}

impl IntoResponse for ProjectError {
    fn into_response(self) -> Response {
        tracing::error!(error = %self, "Project error");
        (
            StatusCode::INTERNAL_SERVER_ERROR,
            Html("<h1>Something went wrong</h1>".to_string()),
        )
            .into_response()
    }
}

{% extends "base.html" %}

{% block title %}Next Actions -- Todo List{% endblock %}

{% block nav %}
{% include "gtd_nav.html" %}
{% endblock %}

{% block content %}
<div class="next-actions">
    <h1>Next Actions</h1>

    {% if let Some(error) = error_message %}
    <div class="next-actions__error" role="alert">{{ error }}</div>
    {% endif %}

    <div id="next-actions-content">
    <nav class="next-actions__filters" aria-label="Filter by context">
        <ul class="next-actions__filter-list" role="list">
            <li>
                <a href="/next-actions"
                    hx-get="/next-actions"
                    hx-target="#next-actions-content"
                    hx-select="#next-actions-content"
                    hx-swap="outerHTML"
                    hx-push-url="true"
                    {% if selected_context.is_none() %}aria-current="true" class="next-actions__filter-link next-actions__filter-link--active"{% else %}class="next-actions__filter-link"{% endif %}>All</a>
            </li>
            {% for ctx in contexts %}
            <li>
                <a href="/next-actions?context={{ ctx.id }}"
                    hx-get="/next-actions?context={{ ctx.id }}"
                    hx-target="#next-actions-content"
                    hx-select="#next-actions-content"
                    hx-swap="outerHTML"
                    hx-push-url="true"
                    {% if selected_context.as_deref() == Some(ctx.id.as_str()) %}aria-current="true" class="next-actions__filter-link next-actions__filter-link--active"{% else %}class="next-actions__filter-link"{% endif %}>{{ ctx.name }}</a>
            </li>
            {% endfor %}
        </ul>
    </nav>

    {% if !contexts.is_empty() %}
    <form
        method="post"
        action="/next-actions"
        class="next-actions__add"
        hx-post="/next-actions"
        hx-target="#next-actions-list"
        hx-swap="beforeend"
        hx-on::after-request="if(event.detail.successful) { this.querySelector('#next-action-title').value = ''; this.querySelector('#next-action-title').focus(); }"
    >
        <label for="next-action-title">Add next action</label>
        <div class="next-actions__add-row">
            <input
                type="text"
                id="next-action-title"
                name="title"
                placeholder="What's the next action?"
                maxlength="300"
                autocomplete="off"
                class="next-actions__add-input"
            >
            <label for="next-action-context" class="next-actions__context-label">Context</label>
            <select id="next-action-context" name="context_id" class="next-actions__add-context">
                {% for ctx in contexts %}
                <option value="{{ ctx.id }}"{% if selected_context.as_deref() == Some(ctx.id.as_str()) %} selected{% endif %}>{{ ctx.name }}</option>
                {% endfor %}
            </select>
            <button type="submit" class="next-actions__add-submit">Add</button>
        </div>
    </form>
    {% endif %}

    {% if groups.is_empty() %}
    <div class="next-actions__empty-state" id="next-actions-empty-state">
        <p>No next actions yet. Process your <a href="/inbox">inbox</a> to find things to do.</p>
    </div>
    {% endif %}
    <div id="next-actions-list"{% if groups.is_empty() %} hidden{% endif %}>
        {% if selected_context.is_none() %}
        {% for group in groups %}
        <section class="next-actions__group" aria-labelledby="context-heading-{{ group.context_id }}">
            <h2 id="context-heading-{{ group.context_id }}" class="next-actions__context-heading">{{ group.context_name }}</h2>
            <ul class="next-actions__list" role="list">
                {% for action in group.actions %}
                {% include "next_action_item.html" %}
                {% endfor %}
            </ul>
        </section>
        {% endfor %}
        {% else %}
        <ul class="next-actions__list" role="list">
            {% for group in groups %}
            {% for action in group.actions %}
            {% include "next_action_item.html" %}
            {% endfor %}
            {% endfor %}
        </ul>
        {% endif %}
    </div>
    </div>
</div>
{% endblock %}

{% block scripts %}
<script src="/static/js/next-action-focus.js"></script>
{% endblock %}

